sql:
SELECT COUNT(*)
FROM pipeline_executions
WHERE status = 'FAILURE';

SELECT address, protocol
FROM service_registries
WHERE registry_type = 'Consul' AND port > 5000;

SELECT registry_type, AVG(port) AS average_port
FROM service_registries
GROUP BY registry_type;

SELECT *
FROM pipeline_executions
WHERE status = 'SUCCESS' AND start_time > '2023-01-01';

external_knowledge:
- A 'configuration' refers to a set of attributes defined in the registry; 
- A 'change' is any modification made to a configuration; 
- The average change frequency is a measure of how often a configuration is modified, either by a user or across all users; 
- 'Last 24 hours' refers to the time period from the current timestamp minus one day to the current timestamp.

sql:
SELECT attribute, url_param 
FROM registry_configurations 
WHERE registry_id = 1;

SELECT rc.attribute, dv.default_value
FROM registry_configurations rc
LEFT JOIN default_values dv ON rc.attribute = dv.attribute;

SELECT *
FROM service_registries
ORDER BY registry_id DESC;
